#nullable enable // autogenerated

using MVZ2.GameContent.Entities;
using MVZ2.Vanilla.Entities;
using PVZEngine.Definitions;
using PVZEngine.Entities;
using PVZEngine.Level;

namespace MVZ2.GameContent.Enemies
{
    [AutoEntityBehaviourDefinition(VanillaEnemyNames.HostZombie)]
    public class HostZombie : AIEntityBehaviour
    {
        public HostZombie(string nsp, string name) : base(nsp, name)
        {
        }

        public override void Init(Entity entity)
        {
            base.Init(entity);
            entity.InflictRegenerationBuff(2f, 60000, new EntitySourceReference(entity));
        }

    }
}
